  Future<String> _uploadToS3(File file, String key) async {
    final bytes = await file.readAsBytes();
    final contentType = _contentTypeFromPath(file.path);

    final now = DateTime.now().toUtc();
    final amzDate =
        '${now.year.toString().padLeft(4, '0')}${now.month.toString().padLeft(2, '0')}${now.day.toString().padLeft(2, '0')}T${now.hour.toString().padLeft(2, '0')}${now.minute.toString().padLeft(2, '0')}${now.second.toString().padLeft(2, '0')}Z';
    final dateStamp =
        '${now.year.toString().padLeft(4, '0')}${now.month.toString().padLeft(2, '0')}${now.day.toString().padLeft(2, '0')}';

    final host = '$s3Bucket.s3.$awsRegion.amazonaws.com';
    final canonicalUri = '/${Uri.encodeComponent(key).replaceAll('%2F', '/')}';
    final payloadHash = sha256.convert(bytes).toString();

    final canonicalHeaders =
        'host:$host\nx-amz-content-sha256:$payloadHash\nx-amz-date:$amzDate\n';
    final signedHeaders = 'host;x-amz-content-sha256;x-amz-date';
    final canonicalRequest =
        'PUT\n$canonicalUri\n\n$canonicalHeaders\n$signedHeaders\n$payloadHash';

    final algorithm = 'AWS4-HMAC-SHA256';
    final credentialScope = '$dateStamp/$awsRegion/s3/aws4_request';
    final stringToSign =
        '$algorithm\n$amzDate\n$credentialScope\n${sha256.convert(utf8.encode(canonicalRequest)).toString()}';

    final signingKey = _getSignatureKey(awsSecretKey, dateStamp, awsRegion, 's3');
    final signature =
        Hmac(sha256, signingKey).convert(utf8.encode(stringToSign)).toString();

    final authorizationHeader =
        '$algorithm Credential=$awsAccessKey/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final uri = Uri.parse('https://$host/$key');
    final response = await http.put(
      uri,
      headers: {
        'Host': host,
        'x-amz-date': amzDate,
        'x-amz-content-sha256': payloadHash,
        'Authorization': authorizationHeader,
        'Content-Type': contentType,
      },
      body: bytes,
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('S3 upload failed: ${response.statusCode} ${response.body}');
    }

    return 'https://$host/$key';
  }

  Future<String> _analyzeImage(File file) async {
    final bytes = await file.readAsBytes();
    final base64Image = base64Encode(bytes);

    final uri = Uri.parse(
      'https://vision.googleapis.com/v1/images:annotate?key=$googleVisionApiKey',
    );

    final body = {
      'requests': [
        {
