            {'type': 'TEXT_DETECTION', 'maxResults': 10},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 10},
            {'type': 'OBJECT_LOCALIZATION', 'maxResults': 10},
          ],
        }
      ]
    };

    final response = await http.post(
      uri,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(body),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('Vision API failed: ${response.statusCode} ${response.body}');
    }

    final decoded = jsonDecode(response.body) as Map<String, dynamic>;
    final responses = decoded['responses'] as List<dynamic>;
    if (responses.isEmpty) return 'No analysis results.';
    final res = responses.first as Map<String, dynamic>;

    final buffer = StringBuffer();

    final labels = (res['labelAnnotations'] as List<dynamic>?) ?? [];
    if (labels.isNotEmpty) {
      buffer.writeln('Labels:');
      for (final item in labels.take(5)) {
        final m = item as Map<String, dynamic>;
        buffer.writeln('- ${m['description']} (${(m['score'] as num).toStringAsFixed(2)})');
      }
      buffer.writeln();
    }

    final texts = (res['textAnnotations'] as List<dynamic>?) ?? [];
    if (texts.isNotEmpty) {
      buffer.writeln('Text:');
      buffer.writeln((texts.first as Map<String, dynamic>)['description'] ?? '');
      buffer.writeln();
    }

    final safeSearch = res['safeSearchAnnotation'] as Map<String, dynamic>?;
    if (safeSearch != null) {
      buffer.writeln('Safe Search:');
      safeSearch.forEach((key, value) {
        buffer.writeln('- $key: $value');
      });
      buffer.writeln();
    }

    final objects = (res['localizedObjectAnnotations'] as List<dynamic>?) ?? [];
    if (objects.isNotEmpty) {
      buffer.writeln('Objects:');
      for (final item in objects.take(5)) {
        final m = item as Map<String, dynamic>;
        buffer.writeln('- ${m['name']} (${(m['score'] as num).toStringAsFixed(2)})');
      }
    }

    return buffer.isEmpty ? 'No analysis results found.' : buffer.toString().trim();
  }

  String _contentTypeFromPath(String path) {
    final ext = p.extension(path).toLowerCase();
    switch (ext) {
      case '.jpg':
      case '.jpeg':
        return 'image/jpeg';
      case '.png':
        return 'image/png';
      case '.gif':
        return 'image/gif';
      case '.webp':
        return 'image/webp';
      default:
        return 'application/octet-stream';
    }
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = Hmac(sha256, utf8.encode('AWS4$key')).convert(utf8.encode(dateStamp)).bytes;
    final kRegion = Hmac(sha256, kDate).convert(utf8.encode(regionName)).bytes;
    final kService = Hmac(sha256, kRegion).convert(utf8.encode(serviceName)).bytes;
    final kSigning = Hmac(sha256, kService).convert(utf8.encode('aws4_request')).bytes;
    return kSigning;
  }

